        assert!(typed.to_string().contains("event: message"));
        assert!(typed.to_string().contains("id: 1"));

        let multiline = Event::new("line1\nline2");
        assert!(multiline.to_string().contains("data: line1\n"));
        assert!(multiline.to_string().contains("data: line2\n"));
