        let key = "dGhlIHNhbXBsZSBub25jZQ==";
        let accept = compute_accept_key(key);
        assert_eq!(accept, "s3pPLMBiTxaQ9kYGzzhZRbK+xOo=");
    }

    #[tokio::test]
    async fn websocket_send_recv() {
        let (tx1, rx1) = mpsc::channel(16);
        let (tx2, rx2) = mpsc::channel(16);

        let mut ws = WebSocket {
            rx: rx1,
            tx: tx2,
            closed: false,
        };

        // Simulate receiving a message
        tx1.send(Ok(Message::text("hello"))).await.unwrap();

        let msg = ws.recv().await.unwrap().unwrap();
        assert_eq!(msg.into_text(), Some("hello".into()));

        // Send a message
        ws.send_text("world").await.unwrap();
        let sent = rx2.recv().await.unwrap();
        assert_eq!(sent.into_text(), Some("world".into()));
    }
