/// Run all conformance tests with aggregated reporting
pub fn run_conformance_suite<T: ConformanceTarget>() -> SuiteResult {
    init_test_logging();

    tracing::info!("╔══════════════════════════════════════════════════════════════╗");
    tracing::info!("║     ASUPERSYNC CONFORMANCE TEST SUITE                        ║");
    tracing::info!("║     Target: {}
", std::any::type_name::<T>());
    tracing::info!("╚══════════════════════════════════════════════════════════════╝");

    let mut results = Vec::new();
    let start = Instant::now();

    // Region lifecycle tests
    tracing::info!("\n═══ CATEGORY: Region Lifecycle ═══");
    results.extend(run_region_tests::<T>());

    // Cancellation tests
    tracing::info!("\n═══ CATEGORY: Cancellation Protocol ═══");
    results.extend(run_cancellation_tests::<T>());

    // Outcome tests
    tracing::info!("\n═══ CATEGORY: Outcome Semantics ═══");
    results.extend(run_outcome_tests::<T>());

    // Obligation tests
    tracing::info!("\n═══ CATEGORY: Obligation System ═══");
    results.extend(run_obligation_tests::<T>());

    // Budget tests
    tracing::info!("\n═══ CATEGORY: Budget Enforcement ═══");
    results.extend(run_budget_tests::<T>());

    // Two-phase commit tests
    tracing::info!("\n═══ CATEGORY: Two-Phase Commit ═══");
    results.extend(run_two_phase_tests::<T>());

    let total_duration = start.elapsed();
    let passed = results.iter().filter(|r| r.passed).count();
    let failed = results.len() - passed;

    // Summary
    tracing::info!("\n╔══════════════════════════════════════════════════════════════╗");
    tracing::info!("║                    SUITE SUMMARY                              ║");
    tracing::info!("╠══════════════════════════════════════════════════════════════╣");
    tracing::info!("║ Total tests:  {:4}
", results.len());
    tracing::info!("║ Passed:       {:4}
", passed);
    tracing::info!("║ Failed:       {:4}
", failed);
    tracing::info!("║ Duration:     {:4}ms
", total_duration.as_millis());
    tracing::info!("╚══════════════════════════════════════════════════════════════╝");

    if failed > 0 {
        tracing::error!("\nFAILED TESTS:");
        for result in results.iter().filter(|r| !r.passed) {
            tracing::error!(
                "  ✗ {} (spec: {})",
                result.test_name,
                result.spec_section
            );
        }
    }

    SuiteResult {
        total: results.len(),
        passed,
        failed,
        duration: total_duration,
        results,
    }
}
