mkdir -p "$OUTPUT_DIR"

TIMESTAMP=$(date +%Y%m%d_%H%M%S)
LOG_FILE="$OUTPUT_DIR/conformance_$TIMESTAMP.log"
JSON_FILE="$OUTPUT_DIR/conformance_$TIMESTAMP.json"

echo ""
echo "▶ Running conformance suite..."
echo "  Log file: $LOG_FILE"
echo "  Results:  $JSON_FILE"
echo ""

# Run tests with JSON output
cargo test conformance     --features test-internals     -- --nocapture     2>&1 | tee "$LOG_FILE"

# Parse results and generate JSON report
echo ""
echo "▶ Generating report..."

# Extract test results
PASSED=$(grep -c "test .* ok" "$LOG_FILE" || echo 0)
FAILED=$(grep -c "test .* FAILED" "$LOG_FILE" || echo 0)
IGNORED=$(grep -c "test .* ignored" "$LOG_FILE" || echo 0)

# Create JSON report
cat > "$JSON_FILE" << EOF
{
  "timestamp": "$(date -Iseconds)",
  "suite": "asupersync-conformance",
  "version": "$(cargo pkgid | sed 's/.*#//')",
  "results": {
    "total": $((PASSED + FAILED)),
    "passed": $PASSED,
    "failed": $FAILED,
    "ignored": $IGNORED
  },
  "log_file": "$LOG_FILE"
}
EOF

echo ""
echo "═══════════════════════════════════════════════════════════════"
echo "                    CONFORMANCE RESULTS                        "
echo "═══════════════════════════════════════════════════════════════"
echo "  Passed:  $PASSED"
echo "  Failed:  $FAILED"
echo "  Ignored: $IGNORED"
echo "═══════════════════════════════════════════════════════════════"

if [ "$FAILED" -gt 0 ]; then
    echo ""
    echo "FAILED TESTS:"
    grep "FAILED" "$LOG_FILE" || true
    echo ""
    echo "See $LOG_FILE for details"
    exit 1
fi

echo ""
echo "✓ All conformance tests passed!"
